import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import '../../styles/Navbar.css';

const Navbar = () => {
  const [openMenu, setOpenMenu] = useState(null);
  const location = useLocation();

  const toggleSubMenu = (menu) => {
    setOpenMenu(openMenu === menu ? null : menu);
  };

  const isActive = (path) => {
    return location.pathname === path ? 'active' : '';
  };

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <div className="navbar-brand">
          <Link to="/" className="brand-link">
            <span className="brand-icon">🏥</span>
            <span className="brand-text">Enrollment App</span>
          </Link>
        </div>

        <div className="navbar-menu">
          {/* Menu Dashboard */}
          <div className="nav-item">
            <Link to="/dashboard" className={`nav-link ${isActive('/dashboard') || isActive('/')}`}>
              📊 Dashboard
            </Link>
          </div>

          {/* Menu Policy Inquiry dengan Sub Menu */}
          <div className="nav-item dropdown">
            <button 
              className={`nav-link dropdown-btn ${isActive('/policy') ? 'active' : ''}`}
              onClick={() => toggleSubMenu('policy')}
            >
              📋 Policy Inquiry {openMenu === 'policy' ? '▲' : '▼'}
            </button>
            <div className={`dropdown-menu ${openMenu === 'policy' ? 'show' : ''}`}>
              <Link to="/policy/payor" className="dropdown-item">Registrasi Payor</Link>
              <Link to="/policy/plan" className="dropdown-item">Registrasi Plan</Link>
              <Link to="/policy/participant" className="dropdown-item">Registrasi Participant</Link>
            </div>
          </div>

          {/* Menu Claim Inquiry dengan Sub Menu */}
          <div className="nav-item dropdown">
            <button 
              className={`nav-link dropdown-btn ${isActive('/claim') ? 'active' : ''}`}
              onClick={() => toggleSubMenu('claim')}
            >
              📄 Claim Inquiry {openMenu === 'claim' ? '▲' : '▼'}
            </button>
            <div className={`dropdown-menu ${openMenu === 'claim' ? 'show' : ''}`}>
              <Link to="/claim/summary" className="dropdown-item">Summary</Link>
              <Link to="/claim/history" className="dropdown-item">History Claim</Link>
            </div>
          </div>

          {/* Menu Report */}
          <div className="nav-item">
            <Link to="/report" className={`nav-link ${isActive('/report')}`}>
              📈 Report
            </Link>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
